import{_ as i}from"./plugin-vue_export-helper.21dcd24c.js";import{r,o as n,c as t,a as e,b as d,e as o,d as p}from"./app.dbe422c1.js";const h={},l=o('<h1 id="\u5B57\u8282\u8DF3\u52A8-\u5185\u63A8" tabindex="-1"><a class="header-anchor" href="#\u5B57\u8282\u8DF3\u52A8-\u5185\u63A8" aria-hidden="true">#</a> \u5B57\u8282\u8DF3\u52A8-\u5185\u63A8</h1><p>\u6B22\u8FCE\u6765\u5B57\u8282\u8DF3\u52A8\uFF0C\u548C\u4F5C\u8005\uFF08wendux\uFF09 \u4E00\u8D77\u505A\u540C\u4E8B\uFF01\u6211\u4EEC\u6709\u5927\u91CFHC\uFF0C\u793E\u62DB\u3001\u6821\u62DB\u3001\u5B9E\u4E60\uFF0C\u524D\u7AEF\u3001\u5BA2\u6237\u7AEF\u3001\u540E\u7AEF\u90FD\u6709\uFF0C\u6B22\u8FCE\u5BF9\u6280\u672F\u6709\u70ED\u60C5\u7684\u540C\u5B66\u6765\u6295\u9012\uFF01\u98CE\u91CC\u96E8\u91CC\uFF0C\u6211\u5728\u5B57\u8282\u8DF3\u52A8\u7B49\u4F60~</p><blockquote><p>\u6295\u9012\u65B9\u5F0F\uFF1A\u53D1\u9001\u7B80\u5386\u81F3duwen.x@bytedance.com\uFF0C\u5FAE\u4FE1\u8BF7\u6C42\u901A\u8FC7\u540E\uFF0C\u5B57\u8282\u8DF3\u52A8VIP\u901A\u9053\u5C31\u5EFA\u7ACB\u4E86\uFF08\u540E\u7EED\u53D1\u7B80\u5386\u3001\u8FDB\u5EA6\u8DDF\u8FDB\u3001\u95EE\u9898\u54A8\u8BE2\u90FD\u53EF\u4EE5\u76F4\u63A5\u5FAE\u4FE1\u8054\u7CFB\u54E6\uFF09\u3002</p></blockquote><h2 id="\u524D\u7AEF\u56E2\u961F\u4ECB\u7ECD" tabindex="-1"><a class="header-anchor" href="#\u524D\u7AEF\u56E2\u961F\u4ECB\u7ECD" aria-hidden="true">#</a> \u524D\u7AEF\u56E2\u961F\u4ECB\u7ECD</h2><p>\u6211\u4EEC\u662F\u5B57\u8282\u8DF3\u52A8-\u5E78\u798F\u91CCFE\u56E2\u961F\uFF0C\u8BDE\u751F\u4E8E2018\u5E749\u6708\uFF0C\u4ECE\u6700\u521D\u76844\u4EBA\u7EC4\u6210\u957F\u5230\u4ECA\u5929\u768430\u591A\u4EBA\uFF0C\u6210\u5458\u5E74\u9F84\u8DE8\u5EA6\u4ECE90\u540E\u523000\u540E\u3002\u6280\u672F\u6808\u8986\u76D6\u5F53\u4E0B\u524D\u7AEF\u4E3B\u6D41\u5168\u65B9\u5411\uFF08Vue\u3001React\u3001Typescript\u3001nodejs\u3001webgl\u3001flutter\u3001\u5C0F\u7A0B\u5E8F)\uFF0C\u56E2\u961F\u5185\u5927\u725B\u591A\u591A\uFF0C\u6280\u672F\u6C1B\u56F4\u6D53\u539A\uFF0C\u6709VR\u4E13\u5BB6\u8001\u5434\u30013D\u6E32\u67D3\u4E00\u54E5\u535A\u54E5\u3001\u300AFlutter\u5B9E\u6218\u300B\u4F5C\u8005wendux\u3001\u6DF1\u8C19 Web \u6846\u67B6\u53CA\u5DE5\u7A0B\u5316\u7684\u8463\u8001\u5E08\u3001\u4EE5\u53CA\u6280\u80FD\u6811\u6EE1\u70B9\u7684\u6770\u54E5\u7B49\u7B49\uFF0C\u8FD8\u6709\uFF0C\u56E2\u961F\u7ECF\u5E38\u7EC4\u7EC7\u7EBF\u4E0B\u5B66\u4E60\u53CA\u5A31\u4E50\u6D3B\u52A8\uFF0C\u662F\u4E00\u4E2A\u5F00\u5FC3\u4E14\u6218\u6597\u529B\u6781\u5F3A\u7684team\u3002\u53EA\u8981\u4F60\u89C9\u5F97\u81EA\u5DF1\u591F\u51FA\u8272\uFF0C\u6216\u60F3\u8BA9\u81EA\u5DF1\u53D8\u5F97\u66F4\u51FA\u8272\uFF0C\u8FD8\u7B49\u4EC0\u4E48\uFF0C\u653E\u8086\u5730\u52A0\u5165\u6211\u4EEC\u5427\u3002</p><h3 id="\u4E1A\u52A1\u7EBF\u4ECB\u7ECD" tabindex="-1"><a class="header-anchor" href="#\u4E1A\u52A1\u7EBF\u4ECB\u7ECD" aria-hidden="true">#</a> \u4E1A\u52A1\u7EBF\u4ECB\u7ECD</h3><p>\u5E78\u798F\u91CC\u662F\u5B57\u8282\u8DF3\u52A8\u65D7\u4E0B\u96C6\u5185\u5BB9\u3001\u793E\u533A\u3001\u5DE5\u5177\u4E8E\u4E00\u4F53\u7684\u623F\u4EA7\u4FE1\u606F\u3001\u670D\u52A1\u3001\u4EA4\u6613\u5E73\u53F0\u3002\u4EA7\u54C1\u57FA\u4E8E\u4E2A\u6027\u5316\u63A8\u8350\u5F15\u64CE\u5411\u7528\u6237\u63A8\u8350\u4F18\u8D28\u7684\u623F\u4EA7\u5185\u5BB9\u548C\u5168\u9762\u3001\u771F\u5B9E\u7684\u623F\u6E90\u4FE1\u606F\uFF0C\u81F4\u529B\u4E8E\u4E3A\u7528\u6237\u63D0\u4F9B\u5168\u9762\u3001\u4E13\u4E1A\u3001\u53EF\u9760\u7684\u8D2D\u623F\u51B3\u7B56\u652F\u6301\u3002</p><p>\u5E78\u798F\u91CC\u59CB\u4E8E2018\u5E748\u6708\uFF0C\u662F\u56FD\u5185\u53D1\u5C55\u6700\u5FEB\u7684\uFF0C\u96C6\u5185\u5BB9\u3001\u793E\u533A\u3001\u5DE5\u5177\u4E8E\u4E00\u4F53\u7684\u623F\u4EA7\u4FE1\u606F\u4E0E\u670D\u52A1\u5E73\u53F0\uFF0C\u4E1A\u52A1\u8986\u76D6\u4E00\u4E8C\u7EBF\u517123\u57CE\uFF0C\u73B0\u7D2F\u79EF\u6CE8\u518C\u7528\u6237\u5343\u4E07\uFF0C\u76EE\u524D\u8FDB\u5165\u9AD8\u901F\u589E\u957F\u671F\u3002</p><h3 id="\u56E2\u961F\u798F\u5229" tabindex="-1"><a class="header-anchor" href="#\u56E2\u961F\u798F\u5229" aria-hidden="true">#</a> \u56E2\u961F\u798F\u5229</h3><p>\u4E94\u9669\u4E00\u91D1\u3001\u8865\u5145\u533B\u7597\u4FDD\u9669\u3001\u5B9A\u671F\u4F53\u68C0\u3001\u5E74\u7EC8\u5956\u3001\u80A1\u7968\u671F\u6743\u3001\u5E26\u85AA\u5E74\u5047\u3001\u5458\u5DE5\u65C5\u6E38\u3001\u4EA4\u901A\u8865\u52A9\u3001\u5305\u5403\u3001\u8282\u65E5\u798F\u5229\u3001\u4F4F\u623F\u8865\u8D34\uFF0C\u4E0D\u9650\u91CF\u96F6\u98DF\u4E0B\u5348\u8336\u3001\u5F39\u6027\u5DE5\u4F5C\u5236</p><h4 id="\u5B9E\u4E60\u751F" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u4E60\u751F" aria-hidden="true">#</a> \u5B9E\u4E60\u751F</h4><ol><li>\u56E2\u961F\u4E3A\u6BCF\u4E00\u4F4D\u5B9E\u4E60\u751F\u63D0\u4F9B\u4E13\u804Cmentor\uFF0C\u624B\u628A\u624B\u5E26\u5165\u5DE5\u4F5C\u4E1A\u52A1\u3002</li><li>\u56E2\u961F\u4E3A\u6CA1\u6709\u57FA\u7840\u7684\u5B9E\u4E60\u751F\u63D0\u4F9B\u201C\u7B51\u57FA\u8BA1\u5212\u201D\u7684\u8BFE\u7A0B\u5B66\u4E60\uFF0C\u8F7B\u677E\u8FDB\u9636\u524D\u7AEF\u6280\u80FD\u3002</li></ol><h2 id="\u804C\u4F4D\u4ECB\u7ECD" tabindex="-1"><a class="header-anchor" href="#\u804C\u4F4D\u4ECB\u7ECD" aria-hidden="true">#</a> \u804C\u4F4D\u4ECB\u7ECD</h2><h3 id="\u804C\u4F4D\u4E00-\u524D\u7AEF\u5F00\u53D1\u5DE5\u7A0B\u5E08-\u6821\u62DB-\u793E\u62DB-\u6025" tabindex="-1"><a class="header-anchor" href="#\u804C\u4F4D\u4E00-\u524D\u7AEF\u5F00\u53D1\u5DE5\u7A0B\u5E08-\u6821\u62DB-\u793E\u62DB-\u6025" aria-hidden="true">#</a> \u804C\u4F4D\u4E00\uFF1A\u524D\u7AEF\u5F00\u53D1\u5DE5\u7A0B\u5E08(\u6821\u62DB/\u793E\u62DB)\u6025</h3><p><strong>\u804C\u4F4D\u63CF\u8FF0:</strong></p><ol><li><p>\u8D1F\u8D23\u79FB\u52A8\u7AEF /PC \u7AEF\u4E1A\u52A1\u7CFB\u7EDF\u3001\u5C0F\u7A0B\u5E8F\u3001\u8DE8\u7AEF\u9875\u9762\u5F00\u53D1\uFF1B</p></li><li><p>\u8D1F\u8D23\u63A8\u52A8\u4E0E\u4F18\u5316\u4E1A\u52A1\u7EBF\u4E2D\u524D\u7AEF\u57FA\u7840\u67B6\u6784\u3001\u7EC4\u4EF6\u62BD\u8C61\u3001\u6280\u672F\u8C03\u7814\uFF1B</p></li><li><p>\u79EF\u6781\u63A8\u52A8\u6539\u8FDB\u4EA7\u54C1\uFF0C\u5305\u62EC\u6280\u672F\u3001\u7528\u6237\u4F53\u9A8C\u3001\u4EA7\u54C1\u7B49\u5404\u4E2A\u7EF4\u5EA6\u7684\u6539\u8FDB\u3002</p></li></ol><p><strong>\u804C\u4F4D\u8981\u6C42:</strong></p><ol><li><p>\u672C\u79D1\u53CA\u4EE5\u4E0A\u5B66\u5386\uFF0C\u8BA1\u7B97\u673A\u3001\u901A\u4FE1\u7B49\u76F8\u5173\u4E13\u4E1A\uFF1B</p></li><li><p>\u719F\u7EC3\u638C\u63E1 EcmaScript\uFF0CCSS\uFF0CHTML\uFF0CDOM\u3001\u7ED8\u56FE\u3001\u52A8\u753B\u3001\u534F\u8BAE\u3001\u5B89\u5168\u3001\u7F51\u7EDC\u3001\u6027\u80FD\u4F18\u5316\u7B49\u524D\u7AEF\u6280\u672F\uFF0C\u5BF9\u4E3B\u6D41\u524D\u7AEF\u6846\u67B6\uFF08 React \\ Vue \u7B49\uFF09\u81F3\u5C11\u4E00\u79CD\u6709\u6DF1\u5165\u5E94\u7528\u5E76\u6DF1\u5165\u7406\u89E3\u5176\u8BBE\u8BA1\u539F\u7406\uFF1B</p></li><li><p>\u6709\u5B89\u5353\u3001iOS \u5F00\u53D1\u7ECF\u9A8C\u6216\u8DE8\u7AEF\u6280\u672Fflutter\u8005\u4F18\u5148\uFF1B</p></li><li><p>\u5BF9\u7528\u6237\u4F53\u9A8C\u3001\u4EA4\u4E92\u64CD\u4F5C\u6D41\u7A0B\uFF0C\u53CA\u7528\u6237\u9700\u6C42\u6709\u4E00\u5B9A\u4E86\u89E3\uFF1B</p></li><li><p>\u79EF\u6781\u4E50\u89C2\uFF0C\u8D23\u4EFB\u5FC3\u5F3A\uFF0C\u5DE5\u4F5C\u8BA4\u771F\u7EC6\u81F4\uFF0C\u5177\u5907\u826F\u597D\u7684\u670D\u52A1\u610F\u8BC6\uFF0C\u5177\u6709\u826F\u597D\u7684\u56E2\u961F\u6C9F\u901A\u4E0E\u534F\u4F5C\u80FD\u529B\uFF1B</p></li><li><p>\u70ED\u7231\u524D\u7AEF\u6280\u672F\uFF0C\u6709\u8F83\u5F3A\u7684\u5B66\u4E60\u80FD\u529B\uFF0C\u6709\u5F3A\u70C8\u7684\u6C42\u77E5\u6B32\u3001\u597D\u5947\u5FC3\u548C\u8FDB\u53D6\u5FC3 \uFF0C\u80FD\u53CA\u65F6\u5173\u6CE8\u548C\u5B66\u4E60\u4E1A\u754C\u6700\u65B0\u7684\u524D\u7AEF\u6280\u672F\u3002</p></li></ol><h3 id="\u804C\u4F4D\u4E8C-\u524D\u7AEF\u5F00\u53D1\u5B9E\u4E60\u751F-\u53EF\u8F6C\u6B63" tabindex="-1"><a class="header-anchor" href="#\u804C\u4F4D\u4E8C-\u524D\u7AEF\u5F00\u53D1\u5B9E\u4E60\u751F-\u53EF\u8F6C\u6B63" aria-hidden="true">#</a> \u804C\u4F4D\u4E8C\uFF1A\u524D\u7AEF\u5F00\u53D1\u5B9E\u4E60\u751F(\u53EF\u8F6C\u6B63)</h3><p><strong>\u804C\u4F4D\u63CF\u8FF0\uFF1A</strong></p><p>1\u3001\u8D1F\u8D23\u5B57\u8282\u8DF3\u52A8-\u5E78\u798F\u91CC\u4E1A\u52A1h5\u3001\u5C0F\u7A0B\u5E8F\u3001\u4E2D\u53F0\u7CFB\u7EDF\u7684\u7EF4\u62A4\u4E0E\u5F00\u53D1\uFF1B</p><p>2\u3001\u8D1F\u8D23\u6839\u636E\u5DF2\u6709\u524D\u7AEF\u9879\u76EE\u7684\u57FA\u7840\u67B6\u6784\u8FDB\u884C\u5408\u7406\u7684\u6280\u672F\u4F18\u5316\uFF1B</p><p>3\u3001\u79EF\u6781\u63A8\u52A8\u6539\u8FDB\u4EA7\u54C1\uFF0C\u5305\u62EC\u6280\u672F\u3001\u7528\u6237\u4F53\u9A8C\u3001\u4EA7\u54C1\u7B49\u5404\u4E2A\u7EF4\u5EA6\u3002</p><p><strong>\u804C\u4F4D\u8981\u6C42\uFF1A</strong></p><p>1\u3001\u8BA1\u7B97\u673A\u57FA\u7840\u624E\u5B9E\uFF1A\u6570\u636E\u7ED3\u6784\u3001\u7B97\u6CD5\u3001\u64CD\u4F5C\u7CFB\u7EDF\uFF1B</p><p>2\u3001\u719F\u6089\u638C\u63E1javascript\u3001ES6 \u8BED\u8A00\u7279\u6027\uFF0C\u719F\u7EC3\u638C\u63E1css\u4E2D\u5E38\u89C1\u5E03\u5C40\u65B9\u5F0F\uFF0C\u4EE5\u53CACSS3\u52A8\u753B\u6280\u672F\uFF1B</p><p>3\u3001\u719F\u7EC3\u638C\u63E1VUE\u6216React\u6280\u672F\uFF08\u975E\u5FC5\u987B\uFF09\uFF1B</p><p>4\u3001\u6709ACM\u7ADE\u8D5B\u4E14\u83B7\u5956\u8005\u4F18\u5148\uFF1B</p><p>5\u3001\u5177\u8F83\u5F3A\u7684\u5B66\u4E60\u80FD\u529B\u3001\u4E3B\u52A8\u3001\u81EA\u9A71\u3001\u6709\u8D23\u4EFB\u5FC3\u3002</p><p><strong>\u5B9E\u4E60\u751F\u57F9\u517B\u8BA1\u5212</strong>\uFF1A</p><p>\u6211\u4EEC\u4F1A\u4E3A\u6BCF\u4E00\u4F4D\u5B9E\u4E60\u751F\u914D\u5907\u4E00\u540Dmentor\u8FDB\u884C\u65E5\u5E38\u51B3\u7591\u89E3\u60D1\u548C\u6307\u5BFC\uFF0C\u540C\u65F6\u6211\u4EEC\u9488\u5BF9\u4E0D\u592A\u719F\u6089\u524D\u7AEF\u7684\u540C\u5B66\u8FDB\u884C\u4E00\u4E2A\u4E13\u95E8\u7684\u3010\u7B51\u57FA\u57F9\u8BAD\u3011\uFF0C\u65E8\u5728\u5E2E\u52A9\u5FEB\u901F\u8865\u9F50\u524D\u7AEF\u57FA\u7840\uFF0C\u4EE5\u53CA\u660E\u786E\u540E\u7EED\u5B66\u4E60\u548C\u6210\u957F\u8DEF\u7EBF\uFF0C\u6709\u8001\u53F8\u673A\u5E26\uFF0C\u4E0D\u8FF7\u8DEF\uFF01</p><h3 id="\u804C\u4F4D\u4E09-web3d\u5F00\u53D1\u5DE5\u7A0B\u5E08-\u6025" tabindex="-1"><a class="header-anchor" href="#\u804C\u4F4D\u4E09-web3d\u5F00\u53D1\u5DE5\u7A0B\u5E08-\u6025" aria-hidden="true">#</a> \u804C\u4F4D\u4E09\uFF1Aweb3D\u5F00\u53D1\u5DE5\u7A0B\u5E08\uFF08\u6025\uFF09</h3><p><strong>\u804C\u4F4D\u63CF\u8FF0\uFF1A</strong></p><ol><li>\u8D1F\u8D23 VR \u770B\u623F\u76F8\u5173\u7684\u4E1A\u52A1\u5F00\u53D1\uFF0C\u5305\u62EC\u6E32\u67D3SDK\u3001\u6807\u6CE8\u5E73\u53F0\u7B49\u3002</li><li>\u8D1F\u8D23 VR \u6570\u636E\u5E73\u53F0\u76F8\u5173\u5F00\u53D1\uFF1A\u5305\u62EC\u6570\u636E\u9884\u5904\u7406</li></ol><p><strong>\u804C\u4F4D\u8981\u6C42\uFF1A</strong></p><ol><li><p>\u719F\u7EC3\u638C\u63E1 JavaScript\uFF0CWebGL\uFF1B</p></li><li><p>\u719F\u6089\u8BA1\u7B97\u673A\u56FE\u5F62\u5B66\uFF0C\u6E32\u67D3\u7BA1\u7EBF/\u7EBF\u6027\u4EE3\u6570\uFF1B</p></li><li><p>\u719F\u6089\u5E38\u7528 Shader \u539F\u7406\u53CA\u7F16\u5199\uFF1B</p></li><li><p>\u719F\u6089\u81F3\u5C11\u4E00\u6B3E H5 \u6E32\u67D3\u5F15\u64CE\uFF0C\u5982ThreeJS\uFF0CBabylon\u7B49\uFF1B</p></li><li><p>\u70ED\u7231\u94BB\u7814\u65B0\u6280\u672F\uFF0C\u6709\u5F3A\u70C8\u7684\u597D\u5947\u5FC3\u548C\u6C42\u77E5\u6B32\uFF0C\u6709\u826F\u597D\u7684\u7F16\u7801\u89C4\u8303\uFF1B</p></li><li><p>\u52A0\u5206\u9879\uFF1A</p><ul><li>\u719F\u6089VR\u770B\u623F\u76F8\u5173\u4E1A\u52A1</li><li>\u719F\u6089\u540E\u7AEF\u5F00\u53D1\uFF08Node\uFF09\u3001\u5BF9\u670D\u52A1\u7A33\u5B9A\u6027\u3001\u5E76\u53D1\u4E86\u89E3\u540C\u5B66\u4F18\u5148\uFF08VR\u6570\u636E\u5E73\u53F0\uFF09\u3002</li><li>\u719F\u6089 ThreeJS\uFF0CBabylon, Unity3D \u6709\u76F8\u5173 3D \u4F5C\u54C1\u6216 DEMO\u3002</li><li>\u5404\u5927\u524D\u7AEF\u6280\u672F\u793E\u533A\u6D3B\u8DC3\u8005\u3001\u6709\u81EA\u5DF1\u7684\u5F00\u6E90\u9879\u76EE\uFF1B</li></ul></li></ol><h2 id="\u5176\u5B83\u804C\u4F4D-\u5B9E\u4E60-\u6821\u62DB-\u793E\u62DB\u5747\u53EF" tabindex="-1"><a class="header-anchor" href="#\u5176\u5B83\u804C\u4F4D-\u5B9E\u4E60-\u6821\u62DB-\u793E\u62DB\u5747\u53EF" aria-hidden="true">#</a> \u5176\u5B83\u804C\u4F4D\uFF08\u5B9E\u4E60/\u6821\u62DB/\u793E\u62DB\u5747\u53EF\uFF09</h2><h3 id="android\u5F00\u53D1\u5DE5\u7A0B\u5E08" tabindex="-1"><a class="header-anchor" href="#android\u5F00\u53D1\u5DE5\u7A0B\u5E08" aria-hidden="true">#</a> Android\u5F00\u53D1\u5DE5\u7A0B\u5E08</h3><p>\u804C\u4F4D\u63CF\u8FF0</p><p>1\u3001\u8D1F\u8D23\u516C\u53F8\u79FB\u52A8\u4EA7\u54C1\u7684\u7814\u53D1, \u7F16\u5199\u9AD8\u8D28\u91CF\u7684\u4EE3\u7801\uFF1B</p><p>2\u3001\u548C\u4EA7\u54C1\u7ECF\u7406\u914D\u5408, \u6DF1\u5EA6\u53C2\u4E0E\u624B\u673A\u4EA7\u54C1\u9700\u6C42\u8BA8\u8BBA, \u529F\u80FD\u5B9A\u4E49\u7B49\uFF1B</p><p>3\u3001\u8BBE\u8BA1\u826F\u597D\u7684\u4EE3\u7801\u7ED3\u6784, \u4E0D\u65AD\u8FED\u4EE3\u91CD\u6784 \u3002</p><p>\u804C\u4F4D\u8981\u6C42</p><p>1\u3001\u667A\u80FD\u624B\u673A\u7231\u597D\u8005\u548C\u4F7F\u7528\u8005, \u8FFD\u6C42\u826F\u597D\u7684\u7528\u6237\u4F53\u9A8C\uFF1B</p><p>2\u3001\u70ED\u7231\u79FB\u52A8\u4EA7\u54C1\u7814\u53D1, \u613F\u610F\u5728\u79FB\u52A8\u5F00\u53D1\u9886\u57DF\u6DF1\u5165\u94BB\u7814, \u5E76\u6210\u4E3A\u4E13\u5BB6\uFF1B</p><p>3\u3001\u719F\u7EC3\u638C\u63E1JAVA, \u719F\u6089Android SDK\uFF1B</p><p>4\u3001\u4E00\u5E74\u4EE5\u4E0AAndroid\u5F00\u53D1\u7ECF\u9A8C, \u80FD\u72EC\u7ACB\u5F00\u53D1Android App\uFF1B 5\u3001\u5BF9\u8F6F\u4EF6\u4EA7\u54C1\u6709\u5F3A\u70C8\u7684\u8D23\u4EFB\u5FC3, \u5177\u5907\u826F\u597D\u7684\u6C9F\u901A\u80FD\u529B\u548C\u4F18\u79C0\u7684\u56E2\u961F\u534F\u4F5C\u80FD\u529B\u3002</p><p>5\u3001\u6709flutter\u5F00\u53D1\u7ECF\u9A8C\u8005\u52A0\u5206\u3002</p><h3 id="ios\u5F00\u53D1\u5DE5\u7A0B\u5E08" tabindex="-1"><a class="header-anchor" href="#ios\u5F00\u53D1\u5DE5\u7A0B\u5E08" aria-hidden="true">#</a> iOS\u5F00\u53D1\u5DE5\u7A0B\u5E08</h3><p>\u804C\u4F4D\u63CF\u8FF0</p><p>1\u3001\u8D1F\u8D23\u516C\u53F8\u79FB\u52A8\u4EA7\u54C1\u7684\u7814\u53D1\uFF0C\u7F16\u5199\u9AD8\u8D28\u91CF\u7684\u4EE3\u7801\uFF1B</p><p>2\u3001\u548C\u4EA7\u54C1\u7ECF\u7406\u914D\u5408\uFF0C\u6DF1\u5EA6\u53C2\u4E0E\u624B\u673A\u4EA7\u54C1\u9700\u6C42\u8BA8\u8BBA\uFF0C\u529F\u80FD\u5B9A\u4E49\u7B49\uFF1B</p><p>3\u3001\u8BBE\u8BA1\u826F\u597D\u7684\u4EE3\u7801\u7ED3\u6784\uFF0C\u4E0D\u65AD\u8FED\u4EE3\u91CD\u6784 \uFF1B</p><p>4\u3001\u5BFC\u5E76\u5E26\u9886\u521D\u7EA7\u5DE5\u7A0B\u5E08\u5171\u540C\u5B8C\u6210\u7814\u53D1\u4EFB\u52A1\u3002</p><p>\u804C\u4F4D\u8981\u6C42</p><p>1\u3001\u6709\u5F3A\u70C8\u7684\u6C42\u77E5\u6B32\u548C\u8FDB\u53D6\u5FC3\uFF1B</p><p>2\u3001\u5177\u6709\u624E\u5B9E\u7684\u7F16\u7A0B\u5DE5\u5E95\uFF0C\u826F\u597D\u7684\u8BBE\u8BA1\u80FD\u529B\u548C\u7F16\u7A0B\u4E60\u60EF\uFF1B</p><p>3\u3001\u81F3\u5C11\u7CBE\u901A\u4E00\u95E8\u7F16\u7A0B\u8BED\u8A00 \uFF0C\u719F\u7EC3\u638C\u63E1Objective-C\uFF0C\u719F\u6089Swift\u7684\u4F18\u5148 \uFF1B</p><p>4\u3001\u4E00\u5E74\u4EE5\u4E0AiOS\u5F00\u53D1\u7ECF\u9A8C\uFF0C\u80FD\u72EC\u7ACB\u5F00\u53D1iPhoneApp\u8005\u5148\u3002</p><p>5\u3001\u6709flutter\u5F00\u53D1\u7ECF\u9A8C\u8005\u52A0\u5206\u3002</p><h3 id="\u540E\u7AEF\u5F00\u53D1\u5DE5\u7A0B\u5E08" tabindex="-1"><a class="header-anchor" href="#\u540E\u7AEF\u5F00\u53D1\u5DE5\u7A0B\u5E08" aria-hidden="true">#</a> \u540E\u7AEF\u5F00\u53D1\u5DE5\u7A0B\u5E08</h3><p><strong>\u804C\u4F4D\u63CF\u8FF0</strong></p><p>1\u3001\u4E3B\u5BFC\u6216\u53C2\u4E0E\u7CFB\u7EDF\u8BBE\u8BA1\u3001\u7814\u53D1\u3001\u90E8\u7F72\u7B49\u76F8\u5173\u5DE5\u4F5C\uFF1B</p><p>2\u3001\u7814\u53D1\u57FA\u7840\u670D\u52A1\u7EC4\u4EF6\uFF0C\u89E3\u51B3\u5171\u6027\u9700\u6C42\uFF0C\u51CF\u5C11\u91CD\u590D\u5F00\u53D1\u4E0E\u8FD0\u7EF4\uFF1B</p><p>3\u3001\u6709\u8F83\u5F3A\u7684\u7CFB\u7EDF\u95EE\u9898\u5206\u6790\u7ECF\u9A8C\u548C\u80FD\u529B\uFF0C\u80FD\u591F\u89E3\u51B3\u590D\u6742\u7684\u7CFB\u7EDF\u95EE\u9898\uFF1B</p><p>4\u3001\u53C2\u4E0E\u90E8\u5206\u751F\u4EA7\u7CFB\u7EDF\u7EF4\u62A4\u5DE5\u4F5C\uFF0C\u89E3\u51B3\u751F\u4EA7\u7CFB\u7EDF\u95EE\u9898\u53CA\u8FDB\u884C\u7CFB\u7EDF\u8C03\u4F18\u3002</p><p><strong>\u804C\u4F4D\u8981\u6C42</strong></p><p>1\u3001\u672C\u79D1\u53CA\u4EE5\u4E0A\u5B66\u5386\uFF0C\u8BA1\u7B97\u673A\u76F8\u5173\u4E13\u4E1A\uFF1B</p><p>2\u3001\u70ED\u7231\u8BA1\u7B97\u673A\u79D1\u5B66\u548C\u4E92\u8054\u7F51\u6280\u672F\uFF0C\u7CBE\u901A\u81F3\u5C11\u4E00\u95E8\u7F16\u7A0B\u8BED\u8A00\uFF0C\u5305\u62EC\u4F46\u4E0D\u4EC5\u9650\u4E8E\uFF1AJava\u3001C\u3001C++\u3001PHP\u3001 Python\u3001Go\uFF1B</p><p>3\u3001\u638C\u63E1\u624E\u5B9E\u7684\u8BA1\u7B97\u673A\u57FA\u7840\u77E5\u8BC6\uFF0C\u6DF1\u5165\u7406\u89E3\u6570\u636E\u7ED3\u6784\u3001\u7B97\u6CD5\u548C\u64CD\u4F5C\u7CFB\u7EDF\u77E5\u8BC6\uFF1B</p><p>4\u3001\u6709\u4F18\u79C0\u7684\u903B\u8F91\u5206\u6790\u80FD\u529B\uFF0C\u80FD\u591F\u5BF9\u4E1A\u52A1\u903B\u8F91\u8FDB\u884C\u5408\u7406\u7684\u62BD\u8C61\u548C\u62C6\u5206\uFF1B</p><p>5\u3001\u6709\u5F3A\u70C8\u7684\u6C42\u77E5\u6B32\uFF0C\u4F18\u79C0\u7684\u5B66\u4E60\u548C\u6C9F\u901A\u80FD\u529B\u3002</p>',72),s={id:"\u8FD4\u56DE\u4E66\u7C4D\u83DC\u5355\u5217\u8868",tabindex:"-1"},c=e("a",{class:"header-anchor",href:"#\u8FD4\u56DE\u4E66\u7C4D\u83DC\u5355\u5217\u8868","aria-hidden":"true"},"#",-1),u=p(),f={href:"/index",target:"_blank",rel:"noopener noreferrer"},_=p("\u8FD4\u56DE\u4E66\u7C4D\u83DC\u5355\u5217\u8868");function b(x,g){const a=r("ExternalLinkIcon");return n(),t("div",null,[l,e("h2",s,[c,u,e("a",f,[_,d(a)])])])}var V=i(h,[["render",b],["__file","join_us.html.vue"]]);export{V as default};
